-- ResourceKey full-table validation (count + content)
DO $$
DECLARE
    _actual_count integer;
    _mismatched_count integer;
    _mismatched_ids text;
BEGIN
    SELECT COUNT(*) INTO _actual_count FROM "dms"."ResourceKey";
    IF _actual_count <> 351 THEN
        RAISE EXCEPTION 'dms.ResourceKey count mismatch: expected 351, found %', _actual_count;
    END IF;

    SELECT COUNT(*) INTO _mismatched_count
    FROM "dms"."ResourceKey" rk
    WHERE NOT EXISTS (
        SELECT 1 FROM (VALUES
            (1::smallint, 'Ed-Fi', 'AbsenceEventCategoryDescriptor', '5.2.0'),
            (2::smallint, 'Ed-Fi', 'AcademicHonorCategoryDescriptor', '5.2.0'),
